<?php
$stmt = $pdo->query('SELECT name, email FROM users');

// Associative array
$user = $stmt->fetch(PDO::FETCH_ASSOC);
echo $user['name'];

// Object
$user = $stmt->fetch(PDO::FETCH_OBJ);
echo $user->name;

// Fetch all as objects
$users = $stmt->fetchAll(PDO::FETCH_OBJ);
foreach ($users as $user) {
    echo $user->name;
}
?>
